-- ----------------------------
-- Table structure for server_quest_spawn
-- ----------------------------
CREATE TABLE `server_quest_spawn` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `questid` int(10) NOT NULL DEFAULT '0',
  `is_spawn` tinyint(1) unsigned NOT NULL DEFAULT '1' COMMENT '是否为副本召唤NPC',
  `none` varchar(45) NOT NULL DEFAULT '0',
  `count` int(10) NOT NULL DEFAULT '1',
  `npc_templateid` int(10) NOT NULL DEFAULT '0',
  `group_id` int(10) NOT NULL DEFAULT '0',
  `locx1` int(10) NOT NULL DEFAULT '0',
  `locy1` int(10) NOT NULL DEFAULT '0',
  `locx2` int(10) NOT NULL DEFAULT '0',
  `locy2` int(10) NOT NULL DEFAULT '0',
  `heading` int(10) unsigned NOT NULL DEFAULT '0',
  `respawn_delay` int(10) unsigned NOT NULL DEFAULT '120',
  `mapid` int(10) NOT NULL DEFAULT '0',
  `movement_distance` int(10) unsigned NOT NULL DEFAULT '30',
  `near_spawn` int(10) NOT NULL DEFAULT '1' COMMENT '召唤时是否闪避PC 0:不闪避 1:闪避',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=50277 DEFAULT CHARSET=utf8;

